53	        -----------------------------------------------------------------------------
54	        -- Read address channel
55	        s00_axi_arid                : in    std_logic_vector(C_S00_AXI_ID_WIDTH-1   downto 0);
56	        s00_axi_araddr              : in    std_logic_vector(AxiSlaveAddrWidth_g-1 downto 0);
57	        s00_axi_arlen               : in    std_logic_vector(7 downto 0);
58	        s00_axi_arsize              : in    std_logic_vector(2 downto 0);
59	        s00_axi_arburst             : in    std_logic_vector(1 downto 0);
60	        s00_axi_arlock              : in    std_logic;
61	        s00_axi_arcache             : in    std_logic_vector(3 downto 0);
62	        s00_axi_arprot              : in    std_logic_vector(2 downto 0);
63	        s00_axi_arvalid             : in    std_logic;
64	        s00_axi_arready             : out   std_logic;
65	        -- Read data channel
66	        s00_axi_rid                 : out   std_logic_vector(C_S00_AXI_ID_WIDTH-1 downto 0);
67	        s00_axi_rdata               : out   std_logic_vector(31 downto 0);
68	        s00_axi_rresp               : out   std_logic_vector(1 downto 0);
69	        s00_axi_rlast               : out   std_logic;
70	        s00_axi_rvalid              : out   std_logic;
71	        s00_axi_rready              : in    std_logic;
72	        -- Write address channel
73	        s00_axi_awid                : in    std_logic_vector(C_S00_AXI_ID_WIDTH-1   downto 0);
74	        s00_axi_awaddr              : in    std_logic_vector(AxiSlaveAddrWidth_g-1 downto 0);
75	        s00_axi_awlen               : in    std_logic_vector(7 downto 0);
76	        s00_axi_awsize              : in    std_logic_vector(2 downto 0);
77	        s00_axi_awburst             : in    std_logic_vector(1 downto 0);
78	        s00_axi_awlock              : in    std_logic;
79	        s00_axi_awcache             : in    std_logic_vector(3 downto 0);
80	        s00_axi_awprot              : in    std_logic_vector(2 downto 0);
81	        s00_axi_awvalid             : in    std_logic;
82	        s00_axi_awready             : out   std_logic;
83	        -- Write data channel
84	        s00_axi_wdata               : in    std_logic_vector(31    downto 0);
85	        s00_axi_wstrb               : in    std_logic_vector(3 downto 0);
86	        s00_axi_wlast               : in    std_logic;
87	        s00_axi_wvalid              : in    std_logic;
88	        s00_axi_wready              : out   std_logic;
89	        -- Write response channel
90	        s00_axi_bid                 : out   std_logic_vector(C_S00_AXI_ID_WIDTH-1 downto 0);
91	        s00_axi_bresp               : out   std_logic_vector(1 downto 0);
92	        s00_axi_bvalid              : out   std_logic;
93	        s00_axi_bready              : in    std_logic;
94	
95	        -----------------------------------------------------------------------------
96	        -- Axi Master Bus Interface
97	        -----------------------------------------------------------------------------
98	        -- AXI Read Address Channel
99	        m00_axi_araddr              : out   std_logic_vector(31 downto 0);
100	        m00_axi_arlen               : out   std_logic_vector(7 downto 0);
101	        m00_axi_arsize              : out   std_logic_vector(2 downto 0);
102	        m00_axi_arburst             : out   std_logic_vector(1 downto 0);
103	        m00_axi_arlock              : out   std_logic;
104	        m00_axi_arcache             : out   std_logic_vector(3 downto 0);
105	        m00_axi_arprot              : out   std_logic_vector(2 downto 0);
106	        m00_axi_arvalid             : out   std_logic;
107	        m00_axi_arready             : in    std_logic;
108	        -- AXI Read Data Channel
109	        m00_axi_rdata               : in    std_logic_vector(31 downto 0);
110	        m00_axi_rresp               : in    std_logic_vector(1 downto 0);
111	        m00_axi_rlast               : in    std_logic;
112	        m00_axi_rvalid              : in    std_logic;
113	        m00_axi_rready              : out   std_logic;
